css:
.loader { --speed: var(--loader-speed); --accent: var(--loader-color); --accent-2: var(--loader-secondary-color); width: var(--loader-size); height: var(--loader-size); position: relative; border-radius: 50%; animation: constellation-rotate calc(var(--speed) * 4) linear infinite; }
.loader::before { content: ""; position: absolute; inset: 10%; border-radius: 50%; border: 1px dashed color-mix(in srgb, var(--accent-2) 55%, transparent); }
.loader::after { content: ""; position: absolute; inset: 20%; border-radius: 50%; background: conic-gradient(from 20deg, transparent 0 60%, var(--accent) 75%, transparent 90%); mask: radial-gradient(farthest-side, transparent 62%, #000 64% 72%, transparent 74%); }
.loader span { position: absolute; width: 10%; aspect-ratio: 1; border-radius: 50%; background: #fff; box-shadow: 0 0 12px 3px var(--accent); }
.loader span:nth-child(1){ left:45%; top:0; } .loader span:nth-child(2){ right:5%; top:28%; background:var(--accent-2); } .loader span:nth-child(3){ right:18%; bottom:8%; } .loader span:nth-child(4){ left:14%; bottom:14%; background:var(--accent-2); } .loader span:nth-child(5){ left:0; top:36%; }
@keyframes constellation-rotate { to { rotate: 360deg; } }
